import random
import time
import threading

class Lift:
    def __init__(self, lift_id, num_floors):
        self.lift_id = lift_id
        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.passengers = []  # List of (destination_floor, entry_time)
        self.is_moving = False
        self.lock = threading.Lock()

    def __repr__(self):
        return f"Lift {self.lift_id}: Floor {self.current_floor}, Direction {self.direction}, Passengers: {len(self.passengers)}"

    def call_lift(self, destination_floor, entry_time):
        with self.lock:
            self.passengers.append((destination_floor, entry_time))
            print(f"Time {entry_time:.2f}: Lift {self.lift_id} called to floor {destination_floor} from floor {self.current_floor}")

    def move(self):
        with self.lock:
            if not self.passengers and self.direction == 0:
                return

            self.is_moving = True
            if self.direction == 1:
                next_floor = self.current_floor + 1
            elif self.direction == -1:
                next_floor = self.current_floor - 1
            else: #idle
                if self.passengers:
                    #Determine direction based on first passenger
                    if self.passengers[0][0] > self.current_floor:
                        self.direction = 1
                        next_floor = self.current_floor + 1
                    elif self.passengers[0][0] < self.current_floor:
                        self.direction = -1
                        next_floor = self.current_floor - 1
                    else:
                        next_floor = self.current_floor #stay put
                else:
                    self.is_moving = False
                    return

            if not (1 <= next_floor <= self.num_floors):
                self.direction = -self.direction #reverse direction
                next_floor = self.current_floor + self.direction * -2 #reverse direction

            if not (1 <= next_floor <= self.num_floors):
                self.direction = 0
                self.is_moving = False
                return

            time.sleep(0.5)  # Simulate time taken to move
            self.current_floor = next_floor
            print(f"Time: Lift {self.lift_id} moved to floor {self.current_floor}")

            # Drop off passengers
            dropped_off = []
            for i, (dest_floor, entry_time) in enumerate(self.passengers):
                if dest_floor == self.current_floor:
                    print(f"Time: Lift {self.lift_id} dropped off passenger at floor {self.current_floor}")
                    dropped_off.append(i)

            for index in sorted(dropped_off, reverse=True):
                del self.passengers[index]

            #Check if any passengers are left, if not, set direction to idle
            if not self.passengers:
                self.direction = 0
            self.is_moving = False

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]
        self.call_queue = [] #list of (floor, destination, time)

    def call_lift(self, floor, destination_floor, entry_time):
        self.call_queue.append((floor, destination_floor, entry_time))

    def assign_lift(self, floor, destination_floor, entry_time):
        available_lifts = [lift for lift in self.lifts]
        if not available_lifts:
            print("No lifts available.")
            return

        #Find the lift that is closest to the floor and idle
        best_lift = None
        min_distance = float('inf')
        for lift in available_lifts:
            if lift.direction == 0:
                distance = abs(lift.current_floor - floor)
                if distance < min_distance:
                    min_distance = distance
                    best_lift = lift

        #If no idle lifts, find the closest lift
        if best_lift is None:
            for lift in available_lifts:
                distance = abs(lift.current_floor - floor)
                if distance < min_distance:
                    min_distance = distance
                    best_lift = lift

        if best_lift:
            best_lift.call_lift(destination_floor, entry_time)
            return best_lift
        else:
            print("No lifts available.")
            return None

    def run_lifts(self):
        while True:
            for floor, destination_floor, entry_time in self.call_queue:
                lift = self.assign_lift(floor, destination_floor, entry_time)
                if lift:
                    self.call_queue.remove((floor, destination_floor, entry_time))
            for lift in self.lifts:
                lift.move()
            time.sleep(0.1)

def simulate_building(num_floors, num_lifts, crowd_size, duration):
    building = Building(num_floors, num_lifts)
    lift_thread = threading.Thread(target=building.run_lifts)
    lift_thread.daemon = True
    lift_thread.start()

    start_time = time.time()
    current_time = 0
    while current_time < duration:
        # Simulate different crowd sizes at different times
        if 7 <= current_time % 24 < 9:  # Morning rush
            probability = 0.7 * crowd_size / 100
        elif 12 <= current_time % 24 < 14:  # Lunch rush
            probability = 0.5 * crowd_size / 100
        elif 17 <= current_time % 24 < 19:  # Evening rush
            probability = 0.8 * crowd_size / 100
        elif 22 <= current_time % 24 or current_time % 24 < 6:  # Night
            probability = 0.05 * crowd_size / 100
        else:  # Day
            probability = 0.2 * crowd_size / 100

        if random.random() < probability:
            origin_floor = random.randint(1, num_floors)
            destination_floor = random.randint(1, num_floors)
            while destination_floor == origin_floor:
                destination_floor = random.randint(1, num_floors)

            building.call_lift(origin_floor, destination_floor, current_time)

        time.sleep(0.1)
        current_time = time.time() - start_time

if __name__ == "__main__":
    num_floors = 10
    num_lifts = 3
    crowd_size = 50  # Percentage representing the crowd size
    duration = 60  # Simulation duration in seconds

    simulate_building(num_floors, num_lifts, crowd_size, duration)

