import random
import time

class Lift:
    def __init__(self, lift_id, num_floors):
        self.lift_id = lift_id
        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.is_moving = False

    def __repr__(self):
        return f"Lift {self.lift_id}: Floor {self.current_floor}, Direction {self.direction}, Destinations {self.destination_floors}"

    def add_destination(self, floor):
        if 1 <= floor <= self.num_floors:
            self.destination_floors.append(floor)
            self.destination_floors = sorted(list(set(self.destination_floors))) # Remove duplicates and sort
            if not self.is_moving:
                self.determine_direction()
                self.is_moving = True

    def determine_direction(self):
        if self.destination_floors:
            if self.destination_floors[0] > self.current_floor:
                self.direction = 1
            elif self.destination_floors[0] < self.current_floor:
                self.direction = -1
            else:
                self.direction = 0 # Already at the destination

    def move(self):
        if self.direction == 1:
            self.current_floor += 1
        elif self.direction == -1:
            self.current_floor -= 1

        if self.current_floor in self.destination_floors:
            self.destination_floors.remove(self.current_floor)
            print(f"Lift {self.lift_id}: Arrived at floor {self.current_floor}")

        if not self.destination_floors:
            self.direction = 0
            self.is_moving = False
            print(f"Lift {self.lift_id}: Idle at floor {self.current_floor}")
        else:
            self.determine_direction()

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]
        self.call_queue = [] # (floor, direction)

    def call_lift(self, floor, direction):
        if 1 <= floor <= self.num_floors:
            self.call_queue.append((floor, direction))
            print(f"Call: Floor {floor}, Direction {direction}")
        else:
            print("Invalid floor call.")

    def assign_lift(self, floor, direction):
        available_lifts = [lift for lift in self.lifts if not lift.is_moving]
        if available_lifts:
            # Find the closest available lift
            closest_lift = min(available_lifts, key=lambda lift: abs(lift.current_floor - floor))
            closest_lift.add_destination(floor)
            print(f"Assigned Lift {closest_lift.lift_id} to floor {floor}")
        else:
            # Assign to the lift that will be available soonest
            # This is a simplified approach; a more sophisticated algorithm could be used
            moving_lifts = [lift for lift in self.lifts if lift.is_moving]
            if moving_lifts:
                closest_lift = min(moving_lifts, key=lambda lift: abs(lift.current_floor - floor))
                closest_lift.add_destination(floor)
                print(f"Assigned Lift {closest_lift.lift_id} to floor {floor} (busy, but closest)")
            else:
                print("All lifts are idle, but none are available. This shouldn't happen.")

    def simulate_step(self):
        # Process lift calls
        while self.call_queue:
            floor, direction = self.call_queue.pop(0)
            self.assign_lift(floor, direction)

        # Move lifts
        for lift in self.lifts:
            if lift.is_moving:
                lift.move()

def simulate_office_hours(building, intensity):
    # Simulate morning rush (8-9 AM)
    for _ in range(intensity):
        floor = random.randint(2, building.num_floors)
        building.call_lift(floor, -1)  # Going down

    # Simulate lunch rush (12-1 PM)
    for _ in range(intensity // 2):
        floor = random.randint(1, building.num_floors)
        building.call_lift(floor, 1)  # Going up or down

    # Simulate evening rush (5-6 PM)
    for _ in range(intensity):
        floor = random.randint(2, building.num_floors)
        building.call_lift(floor, -1)  # Going down

    # Simulate some random calls during the day
    for _ in range(intensity // 4):
        floor = random.randint(1, building.num_floors)
        direction = random.choice([1, -1])
        building.call_lift(floor, direction)

