        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.passengers = []  # List of (destination_floor, time_entered)
        self.capacity = 10
        self.log = [] # Log of movements and passenger activity

    def __repr__(self):
        return f"Lift {self.lift_id} (Floor: {self.current_floor}, Direction: {self.direction}, Passengers: {len(self.passengers)})"

    def move(self):
        if self.direction == 1:
            self.current_floor = min(self.current_floor + 1, self.num_floors)
        elif self.direction == -1:
            self.current_floor = max(self.current_floor - 1, 1)

        self.log.append(f"Moved to floor {self.current_floor}")

    def add_passenger(self, destination_floor, current_time):
        if len(self.passengers) < self.capacity:
            self.passengers.append((destination_floor, current_time))
            self.log.append(f"Picked up passenger going to {destination_floor} at time {current_time}")
            return True
        else:
            return False

    def remove_passengers(self, current_time):
        dropped_off = []
        initial_count = len(self.passengers)
        self.passengers = [(dest, enter_time) for dest, enter_time in self.passengers if dest != self.current_floor]
        num_dropped_off = initial_count - len(self.passengers)
        if num_dropped_off > 0:
            self.log.append(f"Dropped off {num_dropped_off} passengers at time {current_time}")
        return num_dropped_off

    def update_direction(self, requests):
        # Prioritize passengers already in the lift
        if self.passengers:
            destinations = [dest for dest, _ in self.passengers]
            highest_destination = max(destinations)
            lowest_destination = min(destinations)

            if self.direction == 1:
                if self.current_floor < highest_destination:
                    self.direction = 1
                elif self.current_floor > lowest_destination:
                    self.direction = -1
                else:
                    self.direction = 0 #Reached all destinations, idle
            elif self.direction == -1:
                if self.current_floor > lowest_destination:
                    self.direction = -1
                elif self.current_floor < highest_destination:
                    self.direction = 1
                else:
                    self.direction = 0 #Reached all destinations, idle
            else: #Idle, choose direction based on closest passenger
                up_requests = [req for req in requests if req > self.current_floor]
                down_requests = [req for req in requests if req < self.current_floor]

                if up_requests and down_requests:
                    closest_up = min(up_requests)
                    closest_down = max(down_requests)
                    if abs(closest_up - self.current_floor) <= abs(closest_down - self.current_floor):
                        self.direction = 1
                    else:
                        self.direction = -1
                elif up_requests:
                    self.direction = 1
                elif down_requests:
                    self.direction = -1
                else:
                    self.direction = 0 #No requests, remain idle
        else: #No passengers, find closest request
            up_requests = [req for req in requests if req > self.current_floor]
            down_requests = [req for req in requests if req < self.current_floor]

            if up_requests and down_requests:
                closest_up = min(up_requests)
                closest_down = max(down_requests)
                if abs(closest_up - self.current_floor) <= abs(closest_down - self.current_floor):
                    self.direction = 1
                else:
                    self.direction = -1
            elif up_requests:
