            with self.lock:
                if self.queue:
                    next_floor = self.queue[0]

                    if next_floor > self.current_floor:
                        self.direction = 1
                    elif next_floor < self.current_floor:
                        self.direction = -1
                    else:
                        self.direction = 0

                    if self.direction == 1:
