import random
import time
import threading

class Skyscraper:
    def __init__(self, num_floors, num_lifts, population_size):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.population_size = population_size
        self.lifts = [Lift(i, num_floors) for i in range(num_lifts)]
        self.floor_populations = [0] * num_floors  # Initial population on each floor
        self.requests = [] # List of lift requests (source, destination)
        self.request_lock = threading.Lock()
        self.simulation_time = 0
        self.simulation_speed = 1 # 1 = real time, 2 = 2x speed, etc.
        self.running = True

    def initialize_population(self):
        # Distribute population randomly across floors
        for _ in range(self.population_size):
            floor = random.randint(0, self.num_floors - 1)
            self.floor_populations[floor] += 1

    def generate_requests(self):
        # Simulate people requesting lifts based on time of day
        time_of_day = self.simulation_time % (24 * 60)  # Time in minutes
        request_probability = 0.0

        # Morning rush hour
        if 480 <= time_of_day <= 600:  # 8:00 - 10:00 AM
            request_probability = 0.05
        # Daytime
        elif 600 < time_of_day <= 1020: # 10:00 AM - 5:00 PM
            request_probability = 0.01
        # Evening rush hour
        elif 1020 < time_of_day <= 1140: # 5:00 PM - 7:00 PM
            request_probability = 0.07
        # Nighttime
        else:
            request_probability = 0.001

        for i in range(self.num_floors):
            num_people_on_floor = self.floor_populations[i]
            for _ in range(num_people_on_floor):
                if random.random() < request_probability:
                    destination_floor = random.randint(0, self.num_floors - 1)
                    while destination_floor == i:
                        destination_floor = random.randint(0, self.num_floors - 1)

                    with self.request_lock:
                        self.requests.append((i, destination_floor))
                    self.floor_populations[i] -= 1 # Person is waiting for lift

    def assign_requests(self):
        with self.request_lock:
            while self.requests:
                source, destination = self.requests.pop(0)
                best_lift = None
                min_distance = float('inf')

                for lift in self.lifts:
                    distance = abs(lift.current_floor - source)
                    if distance < min_distance and lift.status == "idle":
                        min_distance = distance
                        best_lift = lift

                if best_lift:
                    best_lift.add_request(source, destination)
                else:
                    # If no idle lift, put the request back in the queue
                    self.requests.insert(0, (source, destination))
                    #print("No idle lifts, request queued")

    def run_simulation(self, duration_minutes):
        self.initialize_population()
        start_time = time.time()

        while self.simulation_time < duration_minutes * 60 and self.running:
            self.generate_requests()
            self.assign_requests()

            for lift in self.lifts:
                lift.update()

            self.simulation_time += 1
            time.sleep(1 / self.simulation_speed)

        end_time = time.time()
        print(f"Simulation completed in {end_time - start_time:.2f} seconds.")
        self.print_stats()

    def print_stats(self):
        print("\n--- Simulation Statistics ---")
        for i, lift in enumerate(self.lifts):
            print(f"Lift {i}:")
            print(f"  Total distance traveled: {lift.distance_traveled}")
            print(f"  Total passengers carried: {lift.passengers_carried}")
            print(f"  Idle time: {lift.idle_time}")

    def stop_simulation(self):
        self.running = False

class Lift:
