                self.direction = 0
        else:
            self.status = "idle"
            self.direction = 0

    def determine_next_stop(self):
        # Prioritize requests in the current direction
        if self.direction == 1: # Moving up
            possible_stops = [req[0] for req in self.requests if req[0] > self.current_floor]
            if possible_stops:
                return min(possible_stops)
            else:
                # If no more requests in current direction, reverse direction or go idle
                possible_stops = [req[0] for req in self.requests]
                if possible_stops:
                    return min(possible_stops)
                else:
                    return None

        elif self.direction == -1: # Moving down
            possible_stops = [req[0] for req in self.requests if req[0] < self.current_floor]
            if possible_stops:
                return max(possible_stops)
            else:
                # If no more requests in current direction, reverse direction or go idle
                possible_stops = [req[0] for req in self.requests]
                if possible_stops:
                    return max(possible_stops)
                else:
                    return None
        else: # Idle
            if self.requests:
                return self.requests[0][0] # Go to the first request
            else:
                return None

