    def generate_request(self):
        current_hour = time.localtime().tm_hour
        if 7 <= current_hour < 9 or 17 <= current_hour < 19:  # Peak hours (7-9 AM and 5-7 PM)
            request_probability = 0.01 * self.peak_hours_factor * self.crew_size
        elif 9 <= current_hour < 17:  # Off-peak hours (9 AM - 5 PM)
            request_probability = 0.01 * self.off_peak_hours_factor * self.crew_size
        else:  # Night hours (7 PM - 7 AM)
            request_probability = 0.01 * self.night_hours_factor * self.crew_size

        if random.random() < request_probability:
            source_floor = random.randint(1, self.num_floors)
            destination_floor = random.randint(1, self.num_floors)
            while destination_floor == source_floor:
                destination_floor = random.randint(1, self.num_floors)
            return (source_floor, destination_floor)
        return None

    def request_generator(self):
        while self.simulation_running:
            request = self.generate_request()
            if request:
                with self.request_lock:
                    self.requests.append(request)
            time.sleep(0.1)

    def assign_lift(self):
        while self.simulation_running:
            with self.request_lock:
                if self.requests:
                    source_floor, destination_floor = self.requests.pop(0)
                    best_lift = None
                    min_distance = float('inf')
                    for lift in self.lifts:
                        distance = abs(lift.current_floor - source_floor)
                        if distance < min_distance and not lift.is_full():
                            min_distance = distance
                            best_lift = lift

                    if best_lift:
                        best_lift.add_request(source_floor, destination_floor)
                        print(f"Request from {source_floor} to {destination_floor} assigned to Lift {best_lift.id}")
                    else:
                        print(f"No available lift for request from {source_floor} to {destination_floor}. Request discarded.")
            time.sleep(0.2)

    def run_lift(self, lift):
        while self.simulation_running:
            lift.move()
            time.sleep(0.5)

    def start_simulation(self):
        self.simulation_running = True
        request_thread = threading.Thread(target=self.request_generator)
        assign_thread = threading.Thread(target=self.assign_lift)

        self.threads.append(request_thread)
        self.threads.append(assign_thread)

        request_thread.start()
        assign_thread.start()

        for lift in self.lifts:
            lift_thread = threading.Thread(target=self.run_lift, args=(lift,))
            self.threads.append(lift_thread)
            lift_thread.start()

    def stop_simulation(self):
        self.simulation_running = False
        for thread in self.threads:
            thread.join()
        print("Simulation stopped.")

class Lift:
    def __init__(self, id, num_floors, capacity=10):
        self.id = id
        self.current_floor = 1
        self.destination_floors = []
        self.direction = 1  # 1 for up, -1 for down
        self.num_floors = num_floors
        self.capacity = capacity
        self.passengers = 0
        self.requests = []
        self.request_lock = threading.Lock()

    def add_request(self, source_floor, destination_floor):
        with self.request_lock:
            self.requests.append((source_floor, destination_floor))
            self.destination_floors.append(source_floor)
            self.destination_floors.append(destination_floor)
            self.destination_floors = sorted(list(set(self.destination_floors)))

    def move(self):
        if not self.destination_floors:
            return

        next_floor = None
        if self.direction == 1: # Moving up
            possible_floors = [f for f in self.destination_floors if f > self.current_floor]
            if possible_floors:
                next_floor = min(possible_floors)
            else:
                self.direction = -1
                possible_floors = [f for f in self.destination_floors if f < self.current_floor]
                if possible_floors:
                    next_floor = max(possible_floors)
                else:
                    next_floor = self.current_floor # No where to go, stay put.
        else: # Moving down
            possible_floors = [f for f in self.destination_floors if f < self.current_floor]
            if possible_floors:
                next_floor = max(possible_floors)
            else:
                self.direction = 1
                possible_floors = [f for f in self.destination_floors if f > self.current_floor]
                if possible_floors:
                    next_floor = min(possible_floors)
                else:
                    next_floor = self.current_floor # No where to go, stay put.

        if next_floor != self.current_floor:
            if self.direction == 1:
                self.current_floor += 1
            else:
                self.current_floor -= 1
        else:
            pass

        if self.current_floor in self.destination_floors:
            print(f"Lift {self.id} arrived at floor {self.current_floor}")
            self.destination_floors.remove(self.current_floor)
            with self.request_lock:
                for source, dest in list(self.requests):
                    if source == self.current_floor:
                        self.passengers += 1
                        self.requests.remove((source, dest))
                        print(f"Lift {self.id}: Picked up passenger at floor {self.current_floor}. Passengers: {self.passengers}")
                    elif dest == self.current_floor:
                        self.passengers -= 1
                        print(f"Lift {self.id}: Dropped off passenger at floor {self.current_floor}. Passengers: {self.passengers}")

    def is_full(self):
        return self.passengers >= self.capacity

