import random
import time
import threading

class SkyscraperSimulation:
    def __init__(self, num_lifts, num_floors, peak_hours=(7, 9), off_peak_hours=(11, 14), night_hours=(22, 6)):
        self.num_lifts = num_lifts
        self.num_floors = num_floors
        self.lifts = [Lift(i, num_floors) for i in range(num_lifts)]
        self.peak_hours = peak_hours
        self.off_peak_hours = off_peak_hours
        self.night_hours = night_hours
        self.running = False
        self.lock = threading.Lock()

    def start(self, batch_size=5, duration=60):
        self.running = True
        start_time = time.time()
        while self.running and (time.time() - start_time) < duration:
            current_hour = time.localtime().tm_hour
            if self.peak_hours[0] <= current_hour <= self.peak_hours[1] or (self.peak_hours[0] <= current_hour + 24 <= self.peak_hours[1] + 24):
                traffic_intensity = 0.8
            elif self.off_peak_hours[0] <= current_hour <= self.off_peak_hours[1]:
                traffic_intensity = 0.3
            elif self.night_hours[0] <= current_hour <= self.night_hours[1] or (self.night_hours[0] <= current_hour + 24 <= self.night_hours[1] + 24):
                traffic_intensity = 0.05
            else:
                traffic_intensity = 0.5

            num_people = int(random.expovariate(1 / (batch_size * traffic_intensity)))
            if num_people > 0:
                self.generate_requests(num_people)

            self.update_lifts()
            time.sleep(0.1)

        self.running = False
        print("Simulation finished.")

    def stop(self):
        self.running = False

    def generate_requests(self, num_people):
        for _ in range(num_people):
            origin = random.randint(1, self.num_floors)
            destination = random.randint(1, self.num_floors)
            while destination == origin:
                destination = random.randint(1, self.num_floors)

            self.request_lift(origin, destination)

    def request_lift(self, origin, destination):
        available_lifts = [lift for lift in self.lifts if lift.is_available()]
        if available_lifts:
            lift = min(available_lifts, key=lambda l: abs(l.current_floor - origin))
            lift.add_request(origin, destination)
            print(f"Request: From {origin} to {destination}. Assigned to Lift {lift.id}")
        else:
            print(f"Request: From {origin} to {destination}. No lift available.")

    def update_lifts(self):
        for lift in self.lifts:
            lift.move()

class Lift:
    def __init__(self, id, num_floors):
        self.id = id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.requests = []  # List of (origin, destination) tuples
        self.num_floors = num_floors
        self.lock = threading.Lock()

    def add_request(self, origin, destination):
        with self.lock:
            self.requests.append((origin, destination))
            self.requests.sort(key=lambda x: (x[0], x[1])) #Sort by origin, then destination
            if self.direction == 0:
                if origin > self.current_floor:
                    self.direction = 1
                elif origin < self.current_floor:
                    self.direction = -1
                else:
                    if destination > self.current_floor:
                        self.direction = 1
                    else:
                        self.direction = -1

    def move(self):
        with self.lock:
            if not self.requests:
                self.direction = 0
                return

            if self.direction == 1:
                next_floor = self.current_floor + 1
            elif self.direction == -1:
                next_floor = self.current_floor - 1
            else:
                return

            if 1 <= next_floor <= self.num_floors:
                self.current_floor = next_floor
                print(f"Lift {self.id}: Moving to floor {self.current_floor}")

                # Check if we need to pick up or drop off passengers
                requests_to_remove = []
                for origin, destination in self.requests:
                    if origin == self.current_floor:
                        print(f"Lift {self.id}: Picking up passenger at floor {self.current_floor} going to {destination}")
                        requests_to_remove.append((origin, destination))
                    elif destination == self.current_floor:
                        print(f"Lift {self.id}: Dropping off passenger at floor {self.current_floor}")
                        requests_to_remove.append((origin, destination))

