    def add_destination(self, floor):
        if 1 <= floor <= self.num_floors:
            self.destination_floors.append(floor)
            self.destination_floors.sort(key=lambda x: abs(x - self.current_floor)) # Prioritize closer floors

    def move(self):
        if not self.destination_floors:
            self.direction = 0
            self.is_moving = False
            return

        self.is_moving = True
        next_floor = self.destination_floors[0]

        if next_floor > self.current_floor:
            self.direction = 1
            self.current_floor += 1
        elif next_floor < self.current_floor:
            self.direction = -1
            self.current_floor -= 1
        else:
            self.direction = 0
            self.destination_floors.pop(0)
            print(f"Lift {self.lift_id}: Arrived at floor {self.current_floor}")
            time.sleep(1) # Simulate door opening/closing

    def __repr__(self):
        return f"Lift {self.lift_id}: Floor {self.current_floor}, Direction {self.direction}, Destinations {self.destination_floors}"


class Skyscraper:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]
        self.waiting_queues = {floor: [] for floor in range(1, num_floors + 1)} # floor: [(person_id, destination)]
        self.person_counter = 0

    def request_lift(self, start_floor, destination_floor):
        if not (1 <= start_floor <= self.num_floors and 1 <= destination_floor <= self.num_floors and start_floor != destination_floor):
            print("Invalid floor request.")
            return

        self.person_counter += 1
        person_id = self.person_counter
        self.waiting_queues[start_floor].append((person_id, destination_floor))
        print(f"Person {person_id}: Waiting at floor {start_floor} to go to {destination_floor}")

    def assign_lifts(self):
        for floor, waiting_list in self.waiting_queues.items():
            if waiting_list:
                best_lift = None
                min_distance = float('inf')

                for lift in self.lifts:
                    if lift.direction == 0: #idle lift
                        distance = abs(lift.current_floor - floor)
                        if distance < min_distance:
                            min_distance = distance
                            best_lift = lift
                    elif lift.direction == 1 and lift.current_floor <= floor: #lift going up and is below the floor
                        distance = abs(lift.current_floor - floor)
                        if distance < min_distance:
                            min_distance = distance
                            best_lift = lift
                    elif lift.direction == -1 and lift.current_floor >= floor: #lift going down and is above the floor
                        distance = abs(lift.current_floor - floor)
                        if distance < min_distance:
                            min_distance = distance
                            best_lift = lift

                if best_lift:
                    person_id, destination_floor = waiting_list.pop(0)
                    best_lift.add_destination(floor)
                    best_lift.add_destination(destination_floor)
                    print(f"Person {person_id}: Assigned to Lift {best_lift.lift_id}")
                else:
                    print(f"No lift available for floor {floor} at the moment.")

    def simulate_step(self):
        self.assign_lifts()
        for lift in self.lifts:
            lift.move()
            print(lift)

    def simulate(self, num_steps, morning_peak_intensity=5, evening_peak_intensity=7, daytime_intensity=2, nighttime_intensity=0.5):
        for step in range(num_steps):
            print(f"\n--- Step {step + 1} ---")

            # Simulate time of day and adjust request intensity
            if 7 <= step % 24 < 9:  # Morning peak (7-9 AM)
                intensity = morning_peak_intensity
            elif 17 <= step % 24 < 19:  # Evening peak (5-7 PM)
                intensity = evening_peak_intensity
            elif 9 <= step % 24 < 17:  # Daytime (9 AM - 5 PM)
                intensity = daytime_intensity
            else:  # Nighttime
                intensity = nighttime_intensity

            # Generate random lift requests based on intensity
            num_requests = int(random.expovariate(1 / intensity)) # Poisson distribution
            for _ in range(num_requests):
                start_floor = random.randint(1, self.num_floors)
                destination_floor = random.randint(1, self.num_floors)
                while destination_floor == start_floor:
                    destination_floor = random.randint(1, self.num_floors)
                self.request_lift(start_floor, destination_floor)

            self.simulate_step()
            time.sleep(0.5)

