            print(f"Lift {closest_lift.lift_id} dispatched to floor {floor}")
        else:
            # All lifts are busy, add request to the lift with the fewest destinations
            least_busy_lift = min(self.lifts, key=lambda lift: len(lift.destination_floors))
            least_busy_lift.add_destination(floor)
            print(f"All lifts busy. Lift {least_busy_lift.lift_id} will go to floor {floor} after current requests.")

    def run_simulation(self, duration, staff_size):
        start_time = time.time()
        while time.time() - start_time < duration:
            # Simulate lift requests based on time of day and staff size
            current_hour = time.localtime().tm_hour
            if 7 <= current_hour < 9:  # Morning rush
                request_probability = 0.1 * staff_size
            elif 12 <= current_hour < 14:  # Lunch rush
                request_probability = 0.08 * staff_size
            elif 17 <= current_hour < 19:  # Evening rush
                request_probability = 0.12 * staff_size
            else:  # Off-peak hours
                request_probability = 0.01 * staff_size

            if random.random() < request_probability:
                floor = random.randint(1, self.num_floors)
                self.request_lift(floor)

            # Move the lifts
            for lift in self.lifts:
                lift.move()

            time.sleep(0.2)

if __name__ == "__main__":
    num_floors = 10
    num_lifts = 3
    simulation_duration = 60  # seconds
    staff_size = 50

    building = Building(num_floors, num_lifts)
    building.run_simulation(simulation_duration, staff_size)

import random
import time

class Lift:
    def __init__(self, lift_id, num_floors):
        self.lift_id = lift_id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.num_floors = num_floors
        self.is_moving = False

    def add_destination(self, floor):
        if 1 <= floor <= self.num_floors:
            self.destination_floors.append(floor)
            self.destination_floors.sort(key=lambda x: abs(x - self.current_floor))
            if not self.is_moving:
                self.move()

    def move(self):
        self.is_moving = True
        while self.destination_floors:
            next_floor = self.destination_floors.pop(0)
            if next_floor > self.current_floor:
                self.direction = 1
            elif next_floor < self.current_floor:
                self.direction = -1
            else:
                self.direction = 0

            while self.current_floor != next_floor:
                self.current_floor += self.direction
                print(f"Lift {self.lift_id}: Moving to floor {self.current_floor}")
                time.sleep(0.5)  # Simulate travel time

            print(f"Lift {self.lift_id}: Arrived at floor {self.current_floor}")
            time.sleep(1)  # Simulate door opening/closing and people getting in/out

        self.direction = 0
        self.is_moving = False

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]

    def request_lift(self, floor):
        available_lifts = [lift for lift in self.lifts if not lift.is_moving]
        if available_lifts:
            closest_lift = min(available_lifts, key=lambda lift: abs(lift.current_floor - floor))
            print(f"Calling lift {closest_lift.lift_id} to floor {floor}")
            closest_lift.add_destination(floor)
        else:
            idle_lifts = [lift for lift in self.lifts if lift.direction == 0]
            if idle_lifts:
                closest_lift = min(idle_lifts, key=lambda lift: abs(lift.current_floor - floor))
                print(f"Calling lift {closest_lift.lift_id} to floor {floor}")
                closest_lift.add_destination(floor)
            else:
                print("All lifts are busy. Please wait.")

def simulate_lift_activity(num_floors, num_lifts, num_employees):
    building = Building(num_floors, num_lifts)

    def generate_request():
        hour = time.localtime().tm_hour
        if 7 <= hour < 9:  # Morning rush
            probability = 0.7
        elif 12 <= hour < 14:  # Lunch rush
            probability = 0.5
        elif 17 <= hour < 19:  # Evening rush
            probability = 0.6
        else:
            probability = 0.1

        if random.random() < probability:
            floor = random.randint(1, num_floors)
            building.request_lift(floor)

    while True:
        generate_request()
        time.sleep(random.uniform(1, 5))  # Simulate random request intervals

if __name__ == "__main__":
    num_floors = 10
    num_lifts = 2
    num_employees = 50

    simulate_lift_activity(num_floors, num_lifts, num_employees)
